x-codeSamples.source:
curl http://localhost:11434/api/chat -d '{
  "model": "gemma3",
  "messages": [
    {
      "role": "user",
      "content": "why is the sky blue?"
    }
  ]
}'

curl http://localhost:11434/api/chat -d '{
  "model": "gemma3",
  "messages": [
    {
      "role": "user",
      "content": "why is the sky blue?"
    }
  ],
  "stream": false
}'

curl -X POST http://localhost:11434/api/chat -H "Content-Type: application/json" -d '{
  "model": "gemma3",
  "messages": [
    {
      "role": "user",
      "content": "What are the populations of the United States and Canada?"
    }
  ],
  "stream": false,
  "format": {
    "type": "object",
    "properties": {
      "countries": {
        "type": "array",
        "items": {
          "type": "object",
          "properties": {
            "country": {"type": "string"},
            "population": {"type": "integer"}
          },
          "required": ["country", "population"]
        }
      }
    },
    "required": ["countries"]
  }
}'

curl http://localhost:11434/api/chat -d '{
  "model": "qwen3",
  "messages": [
    {
      "role": "user",
      "content": "What is the weather today in Paris?"
    }
  ],
  "stream": false,
  "tools": [
    {
      "type": "function",
      "function": {
        "name": "get_current_weather",
        "description": "Get the current weather for a location",
        "parameters": {
          "type": "object",
          "properties": {
            "location": {
              "type": "string",
              "description": "The location to get the weather for, e.g. San Francisco, CA"
            },
            "format": {
              "type": "string",
              "description": "The format to return the weather in, e.g. 'celsius' or 'fahrenheit'",
              "enum": ["celsius", "fahrenheit"]
            }
          },
          "required": ["location", "format"]
        }
      }
    }
  ]
}'

curl http://localhost:11434/api/chat -d '{
  "model": "gpt-oss",
  "messages": [
    {
      "role": "user",
      "content": "What is 1+1?"
    }
  ],
  "think": "low"
}'

curl http://localhost:11434/api/chat -d '{
  "model": "gemma3",
  "messages": [
    {
      "role": "user",
      "content": "What is in this image?",
      "images": [
        ""
      ]
    }
  ]
}'

curl http://localhost:11434/api/copy -d '{
  "source": "gemma3",
  "destination": "gemma3-backup"
}'

curl http://localhost:11434/api/create -d '{
  "from": "gemma3",
  "model": "alpaca",
  "system": "You are Alpaca, a helpful AI assistant. You only answer with Emojis."
}'

curl http://localhost:11434/api/create -d '{
  "model": "ollama",
  "from": "gemma3",
  "system": "You are Ollama the llama."
}'

curl http://localhost:11434/api/create -d '{
  "model": "llama3.1:8b-instruct-Q4_K_M",
  "from": "llama3.1:8b-instruct-fp16",
  "quantize": "q4_K_M"
}'

curl -X DELETE http://localhost:11434/api/delete -d '{
  "model": "gemma3"
}'

curl http://localhost:11434/api/embed -d '{
  "model": "embeddinggemma",
  "input": "Why is the sky blue?"
}'

curl http://localhost:11434/api/embed -d '{
  "model": "embeddinggemma",
  "input": [
    "Why is the sky blue?",
    "Why is the grass green?"
  ]
}'

curl http://localhost:11434/api/embed -d '{
  "model": "embeddinggemma",
  "input": "Generate embeddings for this text",
  "truncate": true
}'

curl http://localhost:11434/api/embed -d '{
  "model": "embeddinggemma",
  "input": "Generate embeddings for this text",
  "dimensions": 128
}'

curl http://localhost:11434/api/generate -d '{
  "model": "gemma3",
  "prompt": "Why is the sky blue?"
}'

curl http://localhost:11434/api/generate -d '{
  "model": "gemma3",
  "prompt": "Why is the sky blue?",
  "stream": false
}'

curl http://localhost:11434/api/generate -d '{
  "model": "gemma3",
  "prompt": "Why is the sky blue?",
  "options": {
    "temperature": 0.8,
    "top_p": 0.9,
    "seed": 42
  }
}'

curl http://localhost:11434/api/generate -d '{
  "model": "gemma3",
  "prompt": "What are the populations of the United States and Canada?",
  "stream": false,
  "format": {
    "type": "object",
    "properties": {
      "countries": {
        "type": "array",
        "items": {
          "type": "object",
          "properties": {
            "country": {"type": "string"},
            "population": {"type": "integer"}
          },
          "required": ["country", "population"]
        }
      }
    },
    "required": ["countries"]
  }
}'

curl http://localhost:11434/api/generate -d '{
  "model": "gemma3",
  "prompt": "What is in this picture?",
  "images": [""]
}'

curl http://localhost:11434/api/generate -d '{
  "model": "gemma3"
}'

curl http://localhost:11434/api/generate -d '{
  "model": "gemma3",
  "keep_alive": 0
}'

curl http://localhost:11434/api/pull -d '{
  "model": "gemma3"
}'

curl http://localhost:11434/api/pull -d '{
  "model": "gemma3",
  "stream": false
}'

curl http://localhost:11434/api/push -d '{
  "model": "my-username/my-model"
}'

curl http://localhost:11434/api/push -d '{
  "model": "my-username/my-model",
  "stream": false
}'

curl http://localhost:11434/api/show -d '{
  "model": "gemma3"
}'

curl http://localhost:11434/api/show -d '{
  "model": "gemma3",
  "verbose": true
}'
